// Group reminders by charity email and filter to only the
// milestone days: 30, 14, 7, 1.
// Produces one item per (email × grant) pair that needs a reminder today.

const MILESTONE_DAYS = [30, 14, 7, 1];

const rows = $input.all().map(item => item.json);

if (rows.length === 0) {
  console.log('No upcoming deadlines today — nothing to send.');
  return [];
}

const reminders = [];

for (const row of rows) {
  const days = parseInt(row.days_remaining, 10);
  if (!MILESTONE_DAYS.includes(days)) continue;

  let urgency, subject, preheader;

  if (days === 30) {
    urgency   = 'info';
    subject   = `Grant closing in 30 days: ${row.grant_title}`;
    preheader = `You have a month to apply for funding from ${row.grant_funder}.`;
  } else if (days === 14) {
    urgency   = 'medium';
    subject   = `2 weeks left: ${row.grant_title} — are you applying?`;
    preheader = `The deadline is in 14 days. Make sure you're on track.`;
  } else if (days === 7) {
    urgency   = 'high';
    subject   = `⚠️ URGENT: ${row.grant_title} closes in 7 days`;
    preheader = `Act now — this grant closes in one week.`;
  } else if (days === 1) {
    urgency   = 'critical';
    subject   = `🚨 FINAL REMINDER: ${row.grant_title} closes TOMORROW`;
    preheader = `Last chance to apply. Deadline is tomorrow.`;
  }

  reminders.push({
    json: {
      ...row,
      days,
      urgency,
      subject,
      preheader
    }
  });
}

console.log(`Sending ${reminders.length} deadline reminders today`);
return reminders;

// Build urgency-appropriate email HTML.

const r = $input.first().json;

const URGENCY_COLORS = {
  info:     { banner: '#0F4C35', badge: '#00C875', badgeText: '#0D1117',  emoji: '📅' },
  medium:   { banner: '#0F4C35', badge: '#F59E0B', badgeText: '#ffffff', emoji: '📋' },
  high:     { banner: '#B45309', badge: '#F59E0B', badgeText: '#ffffff', emoji: '⚠️' },
  critical: { banner: '#991B1B', badge: '#EF4444', badgeText: '#ffffff', emoji: '🚨' }
};

const c = URGENCY_COLORS[r.urgency] || URGENCY_COLORS.info;

const deadlineFormatted = r.deadline
  ? new Date(r.deadline).toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })
  : 'Unknown';

const awardText = r.max_award
  ? `Up to £${parseInt(r.max_award).toLocaleString()} available`
  : '';

const dashboardUrl = `https://fundsradar.co/pipeline?grant=${r.grant_id}`;

const html = `
<!DOCTYPE html>
<html>
<head><meta charset="utf-8"></head>
<body style="font-family:'Segoe UI',Arial,sans-serif;background:#f4f6f5;margin:0;padding:24px">
  <div style="max-width:560px;margin:0 auto;background:#ffffff;border-radius:16px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.06)">
    <div style="background:${c.banner};padding:28px 36px">
      <div style="display:inline-block;background:${c.badge};color:${c.badgeText};font-weight:bold;font-size:12px;padding:4px 12px;border-radius:20px;text-transform:uppercase;letter-spacing:0.08em;margin-bottom:12px">
        ${r.days} day${r.days !== 1 ? 's' : ''} remaining ${c.emoji}
      </div>
      <h1 style="color:#ffffff;font-size:20px;margin:0;line-height:1.3">${r.grant_title}</h1>
      <p style="color:rgba(255,255,255,0.75);margin:6px 0 0;font-size:14px">${r.grant_funder}</p>
    </div>
    <div style="padding:28px 36px">
      <p style="color:#374151;font-size:15px">Hi ${r.org_name},</p>
      <p style="color:#374151;font-size:15px">The deadline for <strong>${r.grant_title}</strong> is <strong>${deadlineFormatted}</strong> — that's ${r.days} day${r.days !== 1 ? 's' : ''} away.</p>
      ${awardText ? `<p style="color:#374151;font-size:15px">${awardText}.</p>` : ''}
      <div style="background:#f9fafb;border-left:4px solid ${c.badge};border-radius:0 8px 8px 0;padding:14px 18px;margin:20px 0">
        <p style="margin:0;color:#374151;font-size:14px"><strong>Deadline:</strong> ${deadlineFormatted}</p>
        ${awardText ? `<p style="margin:6px 0 0;color:#374151;font-size:14px"><strong>Amount:</strong> ${awardText}</p>` : ''}
      </div>
      <div style="text-align:center;margin:28px 0">
        <a href="${dashboardUrl}" style="display:inline-block;background:${c.banner};color:#ffffff;font-weight:bold;padding:14px 32px;border-radius:10px;text-decoration:none;font-size:15px">View in Pipeline →</a>
      </div>
      <p style="color:#9ca3af;font-size:12px;text-align:center">You're receiving this because you matched this grant on FundsRadar.<br><a href="https://fundsradar.co/settings" style="color:#9ca3af">Manage email preferences</a></p>
    </div>
  </div>
</body>
</html>
`;

return [{ json: { ...r, html } }];
